import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import axios from 'axios';
import html2canvas from 'html2canvas';

const TemplateEditor = () => {
  const { id } = useParams();
  const [template, setTemplate] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [cellContents, setCellContents] = useState({});
  const [imageBase64, setImageBase64] = useState(null);
  const editorRef = useRef(null);

  // 获取模板数据
  useEffect(() => {
    const fetchTemplate = async () => {
      try {
        const response = await axios.get(`/api/template/${id}`);
        setTemplate(response.data);

        // 加载图片并转换为Base64
        const imgResponse = await fetch(`http://localhost:3001${response.data.image}`);
        const blob = await imgResponse.blob();
        const reader = new FileReader();
        reader.onloadend = () => {
          setImageBase64(reader.result);
        };
        reader.readAsDataURL(blob);

        // 初始化格子内容
        const initialContents = {};
        response.data.cells.forEach(cell => {
          const cellKey = `${cell.day}-${cell.index}`;
          initialContents[cellKey] = '';
        });
        setCellContents(initialContents);

        setLoading(false);
      } catch (err) {
        setError('获取模板失败');
        setLoading(false);
      }
    };

    fetchTemplate();
  }, [id]);

  // 更新格子内容
  const handleCellChange = (cellKey, value) => {
    setCellContents(prev => ({
      ...prev,
      [cellKey]: value
    }));
  };

  // 导出为图片
  const handleExport = async () => {
    if (!editorRef.current) {
      setError('编辑器未初始化');
      return;
    }

    try {
      // 显示加载提示
      setError('正在生成图片，请稍候...');

      // 等待图片加载完成
      const img = editorRef.current.querySelector('img');
      if (img) {
        await new Promise((resolve, reject) => {
          if (img.complete) {
            resolve();
          } else {
            img.onload = resolve;
            img.onerror = reject;
          }
        });
      }

      // 临时将输入框内容转换为文本节点，确保导出时显示
      const container = editorRef.current;
      if (!container) {
        setError('容器元素未找到');
        return;
      }

      const cells = container.querySelectorAll('.cell');
      if (!cells || cells.length === 0) {
        setError('未找到任何格子');
        return;
      }

      // 保存原始输入框
      const originalInputs = [];

      cells.forEach(cell => {
        const input = cell.querySelector('input');
        if (input) {
          originalInputs.push({
            cell,
            input,
            value: input.value
          });

          // 创建文本元素替换输入框
          const textDiv = document.createElement('div');
          textDiv.textContent = input.value || '';
          textDiv.style.cssText = `
            width: 100%;
            height: 100%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 14px;
            color: #000;
            font-family: Arial, sans-serif;
            padding: 5px;
            text-align: center;
            word-wrap: break-word;
            overflow: hidden;
            background: transparent;
          `;

          // 临时替换
          cell.removeChild(input);
          cell.appendChild(textDiv);
        }
      });

      // 获取图片的实际尺寸
      let imgWidth = 800;
      let imgHeight = 600;

      if (img) {
        imgWidth = img.naturalWidth || img.width || 800;
        imgHeight = img.naturalHeight || img.height || 600;
      }

      const canvas = await html2canvas(container, {
        backgroundColor: null,
        scale: Math.min(2, 2000 / imgWidth), // 动态调整缩放比例
        logging: true,
        useCORS: true,
        allowTaint: true,
        foreignObjectRendering: false,
        width: imgWidth,
        height: imgHeight,
        windowWidth: imgWidth,
        windowHeight: imgHeight,
        onclone: (clonedDoc) => {
          // 确保克隆的文档中样式正确
          const clonedContainer = clonedDoc.querySelector('.template-editor');
          if (clonedContainer) {
            clonedContainer.style.position = 'relative';
            clonedContainer.style.display = 'inline-block';
          }
        }
      });

      // 恢复原始输入框
      originalInputs.forEach(({ cell, input, value }) => {
        const textDiv = cell.querySelector('div');
        if (textDiv) {
          cell.removeChild(textDiv);
        }
        cell.appendChild(input);
      });

      // 清除加载提示
      setError(null);

      // 创建下载链接
      const link = document.createElement('a');
      link.download = `schedule-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png', 1.0);
      link.click();
    } catch (err) {
      console.error('导出错误:', err);
      setError('导出失败: ' + err.message);
    }
  };

  if (loading) {
    return <div className="loading">加载中...</div>;
  }

  if (error) {
    return <div className="error">{error}</div>;
  }

  if (!template) {
    return <div className="error">模板不存在</div>;
  }

  return (
    <div className="card">
      <div className="toolbar">
        <Link to="/" className="button button-secondary">
          返回列表
        </Link>
        <button 
          className="button button-success"
          onClick={handleExport}
        >
          导出图片
        </button>
      </div>

      <div 
        ref={editorRef}
        className="template-editor"
        style={{ position: 'relative', display: 'inline-block' }}
      >
        <img 
          src={imageBase64 || `http://localhost:3001${template.image}`} 
          alt="模板"
          style={{ display: 'block', maxWidth: '100%', height: 'auto' }}
        />
        {template.cells.map(cell => {
          const cellKey = `${cell.day}-${cell.index}`;
          return (
            <div
              key={cellKey}
              className="cell"
              style={{
                left: cell.x,
                top: cell.y,
                width: cell.width,
                height: cell.height,
                border: 'none',
                background: 'transparent'
              }}
            >
              <input
                type="text"
                id={`cell-${cellKey}`}
                value={cellContents[cellKey] || ''}
                onChange={(e) => handleCellChange(cellKey, e.target.value)}
                placeholder="输入课程"
                style={{
                  width: '100%',
                  height: '100%',
                  border: 'none',
                  background: 'transparent',
                  textAlign: 'center',
                  fontSize: '14px',
                  color: '#000',
                  fontFamily: 'Arial, sans-serif',
                  padding: '5px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default TemplateEditor;
